from flask import Flask, request
app = Flask(__name__)
approved_ips = ['192.168.1.1', '192.168.1.2']
@app.route('/admin')
def admin():
   if request.remote_addr in approved_ips:
       return 'Admin panel'
   else:
       abort(403)
if __name__ == '__main__':
   app.run()
